import click

@click.group()
def cli():
    pass

@cli.command()
def sub():
    pass

with click.Context(cli, info_name='cli', validate_nesting=True) as ctx:
    child = ctx._make_sub_context(sub)
    print('validate_nesting inherited:', child.validate_nesting)
    try:
        ctx.close()
        print('no error raised - BUG')
    except RuntimeError as e:
        print('Got expected RuntimeError:', e)
    child.close()
    ctx.close()
    print('closed fine after child closed')
